// NocoDB v3: { records: [ { id, fields: { order_nr, product, asset, qty, customer, priority, due_date, status } } ] }
var records = msg.payload.records || [];

var statusMap = {
    "Nieuw": "order.created",
    "Bezig": "order.progress",
    "Klaar": "order.closed"
};

var messages = records.map(function(rec) {
    var f = rec.fields || rec;
    var eventType = statusMap[f.status] || "order.created";
    var payload = {
        event_type: eventType,
        line_id: f.asset || "onbekend",
        data: {
            id: f.order_nr,
            product_id: f.product || f.order_nr,
            planned_qty: f.qty || 0,
            customer: f.customer || null,
            priority: f.priority || null,
            due_date: f.due_date || null
        }
    };

    if (eventType === "order.progress" || eventType === "order.closed") {
        payload.data.good_qty = f.qty_completed || 0;
        payload.data.scrap_qty = f.qty_scrap || 0;
    }

    return {
        payload: payload,
        headers: { "Content-Type": "application/json" }
    };
});

node.status({text: records.length + " werkorders → UNS"});
return [messages];
